async function run(input) {
  function esc(s) { return String(s || '').replace(/\\/g, '\\\\').replace(/;/g, '\\;').replace(/,/g, '\\,').replace(/\n/g, '\\n'); }
  var name = String((input && input.name) || '').trim();
  var vorname = String((input && input.vorname) || '').trim();
  var telefon = String((input && input.telefon) || '').trim();
  var email = String((input && input.email) || '').trim();
  var firma = String((input && input.firma) || '').trim();
  var titel = String((input && input.titel) || '').trim();
  var adresse = String((input && input.adresse) || '').trim();
  var website = String((input && input.website) || '').trim();
  if (!name && !vorname && !firma) return { fehler: 'Mindestens name, vorname oder firma noetig.' };
  var fn = (vorname + ' ' + name).trim();
  if (!fn) fn = firma;
  var lines = ['BEGIN:VCARD', 'VERSION:3.0'];
  lines.push('N:' + esc(name) + ';' + esc(vorname) + ';;;');
  lines.push('FN:' + esc(fn));
  if (firma) lines.push('ORG:' + esc(firma));
  if (titel) lines.push('TITLE:' + esc(titel));
  if (telefon) lines.push('TEL;TYPE=CELL:' + esc(telefon));
  if (email) lines.push('EMAIL;TYPE=INTERNET:' + esc(email));
  if (adresse) lines.push('ADR;TYPE=HOME:;;' + esc(adresse) + ';;;;');
  if (website) lines.push('URL:' + esc(website));
  lines.push('END:VCARD');
  var vcard = lines.join('\r\n');
  var base = (fn || 'kontakt').replace(/[^a-zA-Z0-9]+/g, '_').replace(/^_+|_+$/g, '').toLowerCase() || 'kontakt';
  return { vcard: vcard, dateiname: base + '.vcf' };
}
